def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()  # Critical for real-time monitoring
    print(msg, flush=True)  # -u flag compatibility

# =============================================================================
# Cross-Validation Functions
# =============================================================================

def fit_and_evaluate_model(X_train, y_train, X_test, y_test):
    """Fit model on training data and evaluate on test data."""
    try:
        # Add constant for intercept
        X_train_const = sm.add_constant(X_train)
        X_test_const = sm.add_constant(X_test)
        
        # Fit model
        model = sm.OLS(y_train, X_train_const).fit()
        
        # Predictions
        y_train_pred = model.predict(X_train_const)
        y_test_pred = model.predict(X_test_const)
        
        # Training metrics
        train_r2 = r2_score(y_train, y_train_pred)
        
        # Test metrics
        test_r2 = r2_score(y_test, y_test_pred)
        rmse = np.sqrt(mean_squared_error(y_test, y_test_pred))
        mae = mean_absolute_error(y_test, y_test_pred)
        
        # Generalization gap
        generalization_gap = train_r2 - test_r2
        
        return {
            'train_r2': train_r2,
            'test_r2': test_r2,
            'rmse': rmse,
            'mae': mae,
            'generalization_gap': generalization_gap,
            'success': True
        }
        
    except Exception as e:
        log(f"[ERROR] Model fitting failed: {str(e)}")
        return {
            'train_r2': np.nan,
            'test_r2': np.nan,
            'rmse': np.nan,
            'mae': np.nan,
            'generalization_gap': np.nan,
            'success': False
        }

