        X = analysis_clean[X_vars]
        y = analysis_clean['hce_rate']
        
        log(f"[CV_SETUP] Final dataset: {len(X)} observations, {len(X_vars)} predictors")
        
        # Set up cross-validation
        cv = KFold(n_splits=5, shuffle=True, random_state=42)
