        # Expected output: Performance metrics for each fold

        log("[CV_RUN] Running cross-validation...")
        
        cv_results = []
        fold_num = 1
        
        for train_idx, test_idx in cv.split(X):
            log(f"[CV_FOLD] Processing fold {fold_num}/5...")
            
            # Split data
            X_train, X_test = X.iloc[train_idx], X.iloc[test_idx]
            y_train, y_test = y.iloc[train_idx], y.iloc[test_idx]
            
            log(f"[CV_FOLD] Fold {fold_num}: train={len(X_train)}, test={len(X_test)}")
            
            # Fit and evaluate
            fold_result = fit_and_evaluate_model(X_train, y_train, X_test, y_test)
            
            if fold_result['success']:
                fold_result['fold'] = fold_num
